import React, { useEffect, useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { Navigate } from 'react-router-dom';

import RegBlock from './RegBlock';
import LoginBlock from './LoginBlock';

import { fetchMe } from '../store/auth/authActions';

import '../pages/styles/auth.css';

const IndexPage = () => {
  const dispatch = useDispatch();
  const {isAuth, user} = useSelector(state => state.auth);
  const [mode, setMode] = useState('login');

  if (isAuth) {
    return <Navigate to="/app" replace/>;
  }

  return (
	
    <div className="auth-page">
		<div className="head-info-block">
			<p><b>ФИО:</b> Немыкин Ярослав Алексеевич</p>
			<p><b>Группа:</b> P3222</p>
			<p><b>Вариант:</b> 74932</p>
		</div>
	{mode === 'login' ? (
	<>
		<p>Войдите в аккаунт</p>
		<LoginBlock />
		<button
		  className="switch-mode-btn"
		  onClick={()=> setMode('register')}
		>
		Или зарегистрируйтесь, если нет аккаунта
		</button>
	</>
	) : (
	<>
		<p>Зарегистрируйтесь</p>
		<RegBlock />
		<button
		  className="switch-mode-btn"
		  onClick={()=> setMode('login')}
		>
		Или войдите в аккаунт
		</button>
	</>
	)}
	
    </div>
  );
};

export default IndexPage;
